```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // 1. Create a buffer_adaptor from the input span
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));

    // 2. Use the buffer_adaptor's preview function to read the data_type without advancing the read pointer
    adaptor.preview(&result.data_type, 1);

    // 3. Use the buffer_adaptor's size function to check available data size
    // Check if we have at least 5 bytes (1 for data_type + 4 for item_count)
    if (adaptor.size() < 5) {
        return result; // Return empty result if insufficient data
    }

    // 4. Use binary_stream to read the data
    hexi::binary_stream stream(adaptor);

    // Read item_count (uint32_t)
    uint32_t item_count;
    stream >> item_count;

    // 5. Check if buffer has enough data for item_count
    size_t required_size = 4 + (item_count * (result.data_type == 0 ? sizeof(uint32_t) : sizeof(float)));
    if (adaptor.size() < required_size) {
        return result; // Return empty result if insufficient data
    }

    // 6. Read the items based on the data type
    if (result.data_type == 0) {
        // Integers case
        result.int_items.resize(item_count);
        for (auto& item : result.int_items) {
            stream >> item;
        }
    } else {
        // Floats case
        result.float_items.resize(item_count);
        for (auto& item : result.float_items) {
            stream >> item;
        }
    }

    return result;
}
```

