template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Get the actual size of the buffer
    size_t buffer_size = buffer.size();

    // Ensure we don't try to peek more bytes than available
    size_t bytes_to_copy = std::min(bytes_to_peek, buffer_size);

    // Create a vector to hold the peeked data
    std::vector<uint8_t> result(bytes_to_copy);

    // Use the buffer's copy method to peek at data without advancing read pointer
    buffer.copy(result.data(), bytes_to_copy);

    return result;
}
```

