```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer fb(file_path);
    if (!fb) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Check if requested bytes exceed available data
    if (bytes_to_read > fb.size()) {
        bytes_to_read = fb.size(); // Read only available data
    }

    std::vector<uint8_t> result(bytes_to_read);
    fb.read(result.data(), bytes_to_read);

    return result;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer fb(file_path);
    if (!fb) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Check if requested bytes exceed available data
    if (bytes_to_preview > fb.size()) {
        bytes_to_preview = fb.size(); // Preview only available data
    }

    std::vector<uint8_t> result(bytes_to_preview);
    fb.copy(result.data(), bytes_to_preview);

    return result;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    hexi::file_buffer fb(file_path);
    if (fb) {
        fb.write(data.data(), data.size());
    }
    // No action needed if file cannot be opened (error handled internally)
}

