    // Create a vector and reserve space for efficiency
    std::vector<uint32_t> result;
    result.reserve(count);

    // Read the specified number of elements into the vector
    for (uint32_t i = 0; i < count; ++i) {
        uint32_t value;
        reader >> value;
        result.push_back(value);
    }

    return result;
}
